interface WelcomeStepProps {
  onNext: () => void;
}

export function WelcomeStep({ onNext }: WelcomeStepProps) {
  return (
    <div className="flex w-full flex-col items-center gap-6 py-6">
      <div className="flex flex-col items-center gap-3">
        <h1 className="text-[42px] font-extrabold tracking-tight text-white">Deus</h1>
        <p className="max-w-[260px] text-center text-lg leading-relaxed text-white/40">
          Your AI dev team, working in parallel.
        </p>
      </div>

      <button
        onClick={onNext}
        className="mt-4 bg-white px-10 py-3.5 text-sm font-semibold text-black/90 hover:opacity-90 active:scale-[0.97]"
        style={{
          borderRadius: "18px",
          boxShadow:
            "0 0 30px -4px oklch(0.65 0.15 264 / 0.3), 0 2px 12px oklch(0 0 0 / 0.2)",
          transition:
            "transform 200ms cubic-bezier(0.165, 0.84, 0.44, 1), opacity 200ms cubic-bezier(0.165, 0.84, 0.44, 1)",
        }}
      >
        Get Started
      </button>
    </div>
  );
}

