  /* --- Extended background tiers (warm stone) --- */
  --bg-base: #f5f5f4;
  --bg-surface: #fafaf9;
  --bg-elevated: #ffffff;
  --bg-raised: #efefed;
  --bg-overlay: #fafafa;
